t.script:
(function () {
    const searchInput = document.getElementById('resume-search-input');
    if (!searchInput) {
        return;
    }

    const inputWrapper = document.getElementById('resume-search-input-wrapper');
    const chipsContainer = document.getElementById('resume-search-chips');
    const suggestionsBox = document.getElementById('resume-search-suggestions');
    const clearBtn = document.getElementById('resume-search-clear');
    const noResultsBanner = document.getElementById('resume-no-results');

    const teacherDataTag = document.getElementById('resume-teachers-json');
    const filterDataTag = document.getElementById('resume-filters-json');

    let teachersMeta = [];
    let filtersMeta = {};
    let activeFilters = [];

    try {
        teachersMeta = JSON.parse((teacherDataTag && teacherDataTag.textContent) || '[]');
    } catch (err) {
        console.error('Unable to parse resume teacher metadata', err);
    }

    try {
        filtersMeta = JSON.parse((filterDataTag && filterDataTag.textContent) || '{}');
    } catch (err) {
        console.error('Unable to parse resume filter metadata', err);
    }

    const cards = document.querySelectorAll('[data-resume-card]');
    const teacherIndex = teachersMeta.reduce((acc, teacher) => {
        if (teacher && typeof teacher.user_id !== 'undefined') {
            acc[String(teacher.user_id)] = teacher;
        }
        return acc;
    }, {});

    const filterLabels = {
        department: 'Department',
        degree: 'Academic Degree',
        specialization: 'Specialization',
        teacher: 'Faculty'
    };

    const suggestionPool = [];
    Object.entries(filtersMeta || {}).forEach(([type, values]) => {
        if (!Array.isArray(values)) {
            return;
        }
        values.forEach((value) => {
            if (!value) {
                return;
            }
            suggestionPool.push({
                type,
                value,
                label: `${filterLabels[type] || type}: ${value}`,
                term: value.toLowerCase()
            });
        });
    });

    function setWrapperFocus(isFocused) {
        if (!inputWrapper) {
            return;
        }
        if (isFocused) {
            inputWrapper.style.borderColor = '#86b7fe';
            inputWrapper.style.boxShadow = '0 0 0 .25rem rgba(13,110,253,.25)';
        } else {
            inputWrapper.style.borderColor = '';
            inputWrapper.style.boxShadow = '';
        }
    }

    function updateClearButton() {
        if (!clearBtn) {
            return;
        }
        if (activeFilters.length || searchInput.value.trim()) {
            clearBtn.classList.remove('d-none');
        } else {
            clearBtn.classList.add('d-none');
        }
    }

    function matchesFilter(teacher, filter) {
        const valueLower = filter.value.toLowerCase();
        if (filter.type === 'teacher') {
            return !!(teacher && teacher.name && teacher.name.toLowerCase() === valueLower);
        }
        if (filter.type === 'department') {
            return !!(teacher && teacher.department_name && teacher.department_name.toLowerCase() === valueLower);
        }
        if (filter.type === 'degree') {
            return !!(teacher && Array.isArray(teacher.degrees) && teacher.degrees.some((deg) => deg && deg.toLowerCase() === valueLower));
        }
        if (filter.type === 'specialization') {
            return !!(teacher && Array.isArray(teacher.specializations) && teacher.specializations.some((spec) => spec && spec.toLowerCase() === valueLower));
        }
        return false;
    }

    function refreshCards() {
        let visibleCount = 0;
        cards.forEach((card) => {
            const userId = card.getAttribute('data-user-id');
            const teacher = teacherIndex[userId];
            const matches = activeFilters.every((filter) => matchesFilter(teacher, filter));
            if (matches) {
                card.classList.remove('d-none');
                visibleCount += 1;
            } else {
                card.classList.add('d-none');
            }
        });

        if (noResultsBanner) {
            if (visibleCount === 0 && activeFilters.length) {
                noResultsBanner.classList.remove('d-none');
            } else {
                noResultsBanner.classList.add('d-none');
            }
        }
    }

    function renderChips() {
        if (!chipsContainer) {
            return;
        }
        chipsContainer.innerHTML = '';
        activeFilters.forEach((filter, index) => {
            const chip = document.createElement('span');
            chip.className = 'badge bg-light text-dark border resume-filter-chip d-flex align-items-center';
            chip.style.gap = '0.5rem';
            chip.style.padding = '0.35rem 0.6rem';
            chip.style.fontSize = '0.85rem';

            const label = document.createElement('span');
            label.textContent = filter.label;
            chip.appendChild(label);

            const removeBtn = document.createElement('button');
            removeBtn.type = 'button';
            removeBtn.className = 'btn btn-link p-0 text-decoration-none resume-filter-remove';
            removeBtn.setAttribute('aria-label', 'Remove filter');
            removeBtn.dataset.filterIndex = String(index);
            removeBtn.innerHTML = '&times;';
            removeBtn.style.fontSize = '1.1rem';
            removeBtn.style.lineHeight = '1';
            chip.appendChild(removeBtn);

            chipsContainer.appendChild(chip);
        });
    }

    function applyFiltersAndRender() {
        refreshCards();
        renderChips();
        updateClearButton();
    }

    function addFilter(filter) {
        if (!filter) {
            return;
        }
        const exists = activeFilters.some((item) => item.type === filter.type && item.value.toLowerCase() === filter.value.toLowerCase());
        if (exists) {
            return;
        }
        activeFilters.push(filter);
        suggestionsBox.classList.add('d-none');
        searchInput.value = '';
        applyFiltersAndRender();
        searchInput.focus();
    }

    function removeFilterByIndex(index) {
        const numericIndex = parseInt(index, 10);
        if (Number.isNaN(numericIndex)) {
            return;
        }
        activeFilters.splice(numericIndex, 1);
        applyFiltersAndRender();
        searchInput.focus();
    }

    function clearAllFilters() {
        activeFilters = [];
        searchInput.value = '';
        suggestionsBox.classList.add('d-none');
        applyFiltersAndRender();
        searchInput.focus();
    }

    function renderSuggestions(query) {
        const term = (query || '').trim().toLowerCase();
        suggestionsBox.innerHTML = '';
        if (!term) {
            suggestionsBox.classList.add('d-none');
            return;
        }

        const matches = suggestionPool.filter((item) => {
            if (activeFilters.some((filter) => filter.type === item.type && filter.value.toLowerCase() === item.value.toLowerCase())) {
                return false;
            }
            return item.term.includes(term);
        }).slice(0, 8);

        if (!matches.length) {
            suggestionsBox.classList.add('d-none');
            return;
        }

        matches.forEach((item) => {
            const button = document.createElement('button');
            button.type = 'button';
            button.className = 'list-group-item list-group-item-action';
            button.textContent = item.label;
            button.dataset.filterType = item.type;
            button.dataset.filterValue = item.value;
            suggestionsBox.appendChild(button);
        });

        suggestionsBox.classList.remove('d-none');
    }

    if (chipsContainer) {
        chipsContainer.addEventListener('click', (event) => {
            const target = event.target.closest('[data-filter-index]');
            if (target) {
                removeFilterByIndex(target.dataset.filterIndex);
            }
        });
    }

    if (inputWrapper) {
        inputWrapper.addEventListener('click', () => {
            searchInput.focus();
        });
    }

    if (clearBtn) {
        clearBtn.addEventListener('click', () => {
            clearAllFilters();
        });
    }

    searchInput.addEventListener('input', (event) => {
        renderSuggestions(event.target.value);
        updateClearButton();
    });

    searchInput.addEventListener('focus', () => {
        setWrapperFocus(true);
        renderSuggestions(searchInput.value);
    });

    searchInput.addEventListener('blur', () => {
        setWrapperFocus(false);
        setTimeout(() => {
            suggestionsBox.classList.add('d-none');
        }, 150);
    });

    searchInput.addEventListener('keydown', (event) => {
        if (event.key === 'Enter') {
            const firstSuggestion = suggestionsBox.querySelector('button');
            if (firstSuggestion) {
                event.preventDefault();
                addFilter({
                    type: firstSuggestion.dataset.filterType,
                    value: firstSuggestion.dataset.filterValue,
                    label: firstSuggestion.textContent
                });
            }
        } else if (event.key === 'Backspace' && !searchInput.value && activeFilters.length) {
            event.preventDefault();
            activeFilters.pop();
            applyFiltersAndRender();
        }
    });

    document.addEventListener('click', (event) => {
        if (event.target && event.target.closest('#resume-search-suggestions button')) {
            const target = event.target.closest('button');
            addFilter({
                type: target.dataset.filterType,
                value: target.dataset.filterValue,
                label: target.textContent
            });
        } else if (!event.target.closest('.resume-search-box')) {
            suggestionsBox.classList.add('d-none');
        }
    });

    applyFiltersAndRender();
})();
